#!/usr/bin/env python3
import hashlib
from pathlib import Path
import sys
from typing import List, Optional

TARGET_HASH = "a60458d2180258d47d7f7bef5236b33e86711ac926518ca4545ebf24cdc0b76c"

# List of algorithms to try as salts
ALGORITHMS = [
    "sha256",
    "sha3256", 
    "blake256",
    "blake2b256",
    "blake2s256",
    "blake3",
    "streebog256",
    "sm3",
    "gost256",
    "haval256"
]

def try_hash_construction(plaintext: str, salt: str) -> List[tuple[str, str]]:
    """Try different hash constructions and return any matches."""
    results = []

    # Convert inputs to bytes
    plain_bytes = plaintext.encode('utf-8')
    salt_bytes = salt.encode('utf-8')

    # Try different constructions
    constructions = [
        (plain_bytes + salt_bytes, f"{plaintext + salt}"),
        (salt_bytes + plain_bytes, f"{salt + plaintext}")
    ]

    # Try hashlib supported algorithms
    if salt.lower().startswith('sha256'):
        for data, construction in constructions:
            hash_result = hashlib.sha256(data).hexdigest()
            if hash_result == TARGET_HASH:
                results.append((hash_result, construction))

    if salt.lower().startswith('sha3_256') or salt.lower() == 'sha3256':
        for data, construction in constructions:
            hash_result = hashlib.sha3_256(data).hexdigest()
            if hash_result == TARGET_HASH:
                results.append((hash_result, construction))

    if salt.lower().startswith('blake2b'):
        for data, construction in constructions:
            hash_result = hashlib.blake2b(data, digest_size=32).hexdigest()
            if hash_result == TARGET_HASH:
                results.append((hash_result, construction))

    if salt.lower().startswith('blake2s'):
        for data, construction in constructions:
            hash_result = hashlib.blake2s(data, digest_size=32).hexdigest()
            if hash_result == TARGET_HASH:
                results.append((hash_result, construction))

    return results

def main():
    # Check if rockyou.txt exists
    wordlist_paths = [
        '/usr/share/wordlists/rockyou.txt',
        './rockyou.txt'
    ]

    wordlist_path = None
    for path in wordlist_paths:
        if Path(path).exists():
            wordlist_path = path
            break

    if not wordlist_path:
        print("Could not find rockyou.txt wordlist!")
        sys.exit(1)

    print(f"Using wordlist: {wordlist_path}")
    print(f"Target hash: {TARGET_HASH}")
    print("Testing hash constructions...")

    # Process the wordlist
    with open(wordlist_path, 'r', encoding='latin-1') as f:
        for line_num, line in enumerate(f, 1):
            if line_num % 100000 == 0:
                print(f"Processed {line_num} words...")

            word = line.strip()
            if not word:
                continue

            for algorithm in ALGORITHMS:
                results = try_hash_construction(word, algorithm)
                if results:
                    print("\nPOTENTIAL MATCH FOUND!")
                    print(f"Word: {word}")
                    print(f"Algorithm (salt): {algorithm}")
                    for hash_val, construction in results:
                        print(f"Hash: {hash_val}")
                        print(f"Construction: {construction}")
                    print("Flag would be: flag{" + word + "}")
                    print("-" * 50)

if __name__ == "__main__":
    main()
EOF
